// Reconcile the rows inside one .signal-list against a freshly built list, keyed
// by token mint. Existing .signal-row elements are KEPT (only their inner content
// is refreshed, and only when it actually changed), so the browser's native scroll
// anchoring holds the viewport steady (no "pull") and unchanged avatars never
// reload (no flicker). New rows are moved in, gone rows are removed.
function reconcileSignalListRows(liveList, nextList) {
  const rowKey = (el) => el?.dataset?.tokenChart || el?.dataset?.tokenMint || "";
  const existing = new Map();
  for (const el of Array.from(liveList.children)) {
    if (el.classList?.contains("signal-row")) {
      const key = rowKey(el);
      if (key && !existing.has(key)) existing.set(key, el);
    }
  }
  let anchor = liveList.querySelector(":scope > .signal-header") || null;
  const used = new Set();
  for (const nextChild of Array.from(nextList.children)) {
    if (!nextChild.classList?.contains("signal-row")) continue; // header stays as-is
    const key = rowKey(nextChild);
    let live = key ? existing.get(key) : null;
    if (live) {
      used.add(key);
      if (live.className !== nextChild.className) live.className = nextChild.className;
      // Only touch the DOM when the row's content really changed — keeps the
      // element (and its already-painted avatar) intact when nothing moved.
      if (live.innerHTML !== nextChild.innerHTML) live.innerHTML = nextChild.innerHTML;
    } else {
      live = nextChild; // move the freshly built row in (nextList is discarded after)
    }
    if (anchor) {
      if (anchor.nextElementSibling !== live) anchor.after(live);
    } else if (liveList.firstElementChild !== live) {
      liveList.insertBefore(live, liveList.firstElementChild);
    }
    anchor = live;
  }
  for (const [key, el] of existing) {
    if (!used.has(key)) el.remove();
  }
}

// Reconcile the Cooks feed (Best Picks + Newest) in place. Returns false to ask
// for a full rebuild when the section structure changed (rare).
function reconcileCooksFeedInPlace(liveFeed, nextFeed) {
  // Keep the count + "updated Xs ago" line fresh without touching the dropdown,
  // which lives in the section label and stays put across refreshes.
  const liveMeta = liveFeed.querySelector(":scope > [data-cooks-meta]");
  const nextMeta = nextFeed.querySelector(":scope > [data-cooks-meta]");
  if (nextMeta && !liveMeta) liveFeed.insertBefore(nextMeta, liveFeed.firstChild);
  else if (liveMeta && !nextMeta) liveMeta.remove();
  else if (liveMeta && nextMeta && liveMeta.innerHTML !== nextMeta.innerHTML) liveMeta.innerHTML = nextMeta.innerHTML;
  for (const sel of ["[data-cooks-best]", "[data-cooks-newest]"]) {
    const liveSection = liveFeed.querySelector(`:scope > ${sel}`);
    const nextSection = nextFeed.querySelector(`:scope > ${sel}`);
    if (!nextSection) { if (liveSection) liveSection.remove(); continue; }
    if (!liveSection) return false; // a section appeared — let the caller rebuild for correct order
    const liveLabel = liveSection.querySelector(":scope > .cooks-section-label");
    const nextLabel = nextSection.querySelector(":scope > .cooks-section-label");
    if (liveLabel && nextLabel && liveLabel.innerHTML !== nextLabel.innerHTML) liveLabel.innerHTML = nextLabel.innerHTML;
    const liveListEl = liveSection.querySelector(":scope > .signal-list");
    const nextListEl = nextSection.querySelector(":scope > .signal-list");
    if (liveListEl && nextListEl) {
      reconcileSignalListRows(liveListEl, nextListEl);
    } else if (liveListEl !== nextListEl) {
      liveSection.replaceWith(nextSection); // list <-> empty-state swap
    }
  }
  return true;
}

// Tracks the last time the USER scrolled (wheel/touch/keys) so auto-refresh can pin
// the viewport without ever fighting an active scroll.
let lastUserScrollAt = 0;
if (typeof window !== "undefined") {
  const markUserScroll = () => { lastUserScrollAt = Date.now(); };
  window.addEventListener("wheel", markUserScroll, { passive: true });
  window.addEventListener("touchmove", markUserScroll, { passive: true });
  window.addEventListener("keydown", (e) => {
    if (["ArrowDown", "ArrowUp", "PageDown", "PageUp", "Home", "End", " ", "Spacebar"].includes(e.key)) markUserScroll();
  }, { passive: true });
}

// Steady refresh without the full-panel rebuild "shake": on the Cooks tab, update
// the live rows in place (keyed by mint) so the controls, scroll position, and
// painted avatars stay put. Returns true if patched.
function patchLivePairsFeedInPlace() {
  if (state.activeTab !== "live" && state.activeTab !== "terminal") return false;
  const panel = $("[data-panel]");
  const feed = panel?.querySelector(".cooks-feed");
  if (!panel || !feed) return false;
  const activeLivePairs = currentLivePairs();
  const rawRows = uniqueSignalRows(activeLivePairs?.rows || []);
  const allRows = terminalLaunchFilteredRows(rawRows);
  if (!allRows.length) return false; // fall back to full render for empty state
  // Mobile: pin the viewport to a stable on-screen row across the refresh, so new or
  // rotated rows above can't pull the page down. One synchronous correction — touch
  // has no wheel to fight, and there are no delayed passes. Desktop relies on native
  // overflow-anchor (no scrollTo, so it never fights the mouse wheel).
  const compact = isCompactViewport();
  // Capture on-screen anchor rows so an auto-refresh can pin the viewport (no jump)
  // on desktop too — not just mobile.
  const anchors = [];
  {
    const viewportH = window.innerHeight || 700;
    for (const el of feed.querySelectorAll(".signal-row[data-token-chart]")) {
      const top = el.getBoundingClientRect().top;
      if (top >= 80 && top < viewportH) {
        const mint = el.getAttribute("data-token-chart") || "";
        if (mint) anchors.push({ mint, top });
        if (anchors.length >= 6) break;
      }
    }
  }
  const template = document.createElement("div");
  template.innerHTML = cooksFeedHtml(allRows);
  const nextFeed = template.querySelector(".cooks-feed");
  if (!nextFeed || !reconcileCooksFeedInPlace(feed, nextFeed)) {
    feed.outerHTML = cooksFeedHtml(allRows);
  }
  // Pin the viewport on auto-refresh: always on mobile; on desktop only when the
  // user isn't actively scrolling (so a single scrollBy never fights the wheel).
  if (anchors.length && (compact || Date.now() - lastUserScrollAt > 450)) {
    const liveFeed = panel.querySelector(".cooks-feed");
    // Use the first captured row that survived the refresh (best picks can rotate
    // out), and pin it with one scrollBy so nothing above pulls the page.
    for (const a of anchors) {
      const el = liveFeed?.querySelector(`.signal-row[data-token-chart="${a.mint.replace(/["\\]/g, "\\$&")}"]`);
      if (el) {
        const delta = el.getBoundingClientRect().top - a.top;
        if (Number.isFinite(delta) && Math.abs(delta) > 1) window.scrollBy(0, delta);
        break;
      }
    }
  }
  const countLabel = panel.querySelector(".terminal-title-row span");
  if (countLabel) {
    const bucketLabel = LIVE_PAIR_BUCKETS.find(([bucket]) => bucket === state.livePairBucket)?.[1] || "Live";
    countLabel.textContent = `${bucketLabel} | ${allRows.length} live`;
  }
  return true;
}

function scheduleLivePairsRender(reason = "live-pairs-batch") {
  if (reason) {
    livePairsRenderReasons.add(String(reason));
  }
  if (livePairsRenderTimer || livePairsRenderRaf) return;
  const flush = () => {
    const details = Array.from(livePairsRenderReasons);
    livePairsRenderTimer = null;
    livePairsRenderReasons = new Set();
    livePairsRenderRaf = 0;
    if (state.route !== "terminal") return;
    if (!["terminal", "live", "slimeScope"].includes(state.activeTab)) return;
    if (terminalDetailsDrawerOpen()) return;
    recordPerfEvent({
      component: "livePairs",
      action: "batched-live-render",
      durationMs: 0,
      resultCount: Array.isArray(currentLivePairs()?.rows) ? currentLivePairs().rows.length : 0,
      details: details.length ? details.slice(-3).join(" | ") : reason
    });
    // Cooks/Live tab: patch just the rows in place to avoid the panel-rebuild shake.
    // The window scroller naturally stays put when only the inner feed HTML swaps,
    // so the periodic patch must NOT re-anchor scroll here — doing so fights the
    // user's own mouse-wheel/touch scrolling between refreshes.
    if ((state.activeTab === "live" || state.activeTab === "terminal") && patchLivePairsFeedInPlace()) {
      return;
    }
    const scrollSnapshot = captureStableFeedScrollSnapshot();
    render();
    restoreStableFeedScrollSnapshot(scrollSnapshot);
  };
  livePairsRenderTimer = window.setTimeout(() => {
    livePairsRenderRaf = window.requestAnimationFrame(flush);
  }, LIVE_PAIRS_RENDER_DEBOUNCE_MS);
}

const $ = (selector) => document.querySelector(selector);

function runDeferredUiTask(task) {
  window.setTimeout(() => {
    Promise.resolve()
      .then(task)
      .catch((error) => {
        if (typeof setError === "function") {
          setError(error?.message || "Action failed.");
        } else {
          console.warn(error);
        }
      });
  }, 0);
}
const writeText = (element, value) => {
  if (element) element.textContent = value;
};
const setText = (selector, value) => {
  writeText($(selector), value);
};
const setHidden = (selector, hidden) => {
  const element = $(selector);
  if (element) element.hidden = hidden;
};
