// Live Ogre Brief: a glanceable "what is happening right now" strip built entirely
// from state the client already has - zero extra requests.
// --- Ogre Memory: tiny per-device prefs the agent carries between visits -------
// quick-buy size, risk appetite, last tokens looked at. localStorage only - never
// sent anywhere; it just makes the host greeting and replies feel like a regular.
const OGRE_MEMORY_KEY = "slimewire-ogre-memory";

function loadOgreMemory() {
  try {
    return JSON.parse(localStorage.getItem(OGRE_MEMORY_KEY) || "{}") || {};
  } catch {
    return {};
  }
}

function saveOgreMemory(patch = {}) {
  const memory = { ...loadOgreMemory(), ...patch };
  try {
    localStorage.setItem(OGRE_MEMORY_KEY, JSON.stringify(memory));
  } catch {
    // storage full/blocked - memory is a nicety, never an error
  }
  return memory;
}

function ogreMemoryNoteToken(mint, symbol = "") {
  if (!mint) return;
  const memory = loadOgreMemory();
  const recent = (memory.recentTokens || []).filter((item) => item.mint !== mint);
  recent.unshift({ mint, symbol: String(symbol || "").slice(0, 14), at: Date.now() });
  saveOgreMemory({ recentTokens: recent.slice(0, 5) });
}

(function applyOgreMemoryOnBoot() {
  const memory = loadOgreMemory();
  if (memory.quickBuy && !state.quickBuyAmountOverride) state.quickBuyAmountOverride = memory.quickBuy;
})();

function ogreBriefItems() {
  const liveRows = allRawSignalRows();
  const freshLowMc = liveRows.filter((row) => {
    const mc = Number(row.marketCapUsd ?? row.marketCap) || 0;
    return mc > 0 && mc < 8000;
  }).length;
  const plans = Array.isArray(state.tradePlans) ? state.tradePlans : [];
  const watchingPlans = plans.filter((plan) => ["watching", "active"].includes(String(plan.status || "").toLowerCase()));
  const nearTp = watchingPlans.filter((plan) => {
    const move = Number(plan.lastMovePct ?? plan.wallets?.[0]?.lastMovePct);
    const tp = Number(plan.takeProfitPct);
    return Number.isFinite(move) && Number.isFinite(tp) && tp > 0 && move > tp * 0.7;
  }).length;
  const shieldWatching = Number(state.shieldReceipts?.stats?.watching || 0);
  const recentWins = Number(state.proofStats?.wins || 0);
  return [
    recentWins ? `✅ ${recentWins} tracked call(s) hit 2x - the proof wall has receipts` : "",
    freshLowMc ? `🐣 ${freshLowMc} fresh under 8k MC on the feed` : "",
    watchingPlans.length ? `🛡 ${watchingPlans.length} plan(s) armed${nearTp ? ` - ${nearTp} near take-profit` : ""}` : "",
    shieldWatching ? `🔎 ${shieldWatching} flagged token(s) being tracked to outcome` : ""
  ].filter(Boolean);
}

// The agent greets like a host: what changed, what needs attention - once per session.
let ogreAgentHostGreeted = false;
function maybeOgreAgentHostGreeting() {
  if (ogreAgentHostGreeted || ogreAgentMessages().length) return;
  ogreAgentHostGreeted = true;
  const items = ogreBriefItems();
  const memory = loadOgreMemory();
  const memoryBits = [
    memory.quickBuy ? `your quick buy is still ${memory.quickBuy} SOL` : "",
    memory.risk === "degen" ? "serving the early risky ones first, like you asked" : memory.risk === "careful" ? "keeping it shield-clean first, like you asked" : "",
    memory.recentTokens?.[0]?.symbol ? `last visit you were on $${memory.recentTokens[0].symbol}` : ""
  ].filter(Boolean);
  const memoryLine = memoryBits.length ? ` I remember: ${memoryBits.join(", ")}.` : "";
  pushOgreAgentMessage({
    role: "assistant",
    text: items.length
      ? `Welcome back. Right now: ${items.join(". ")}.${memoryLine} Ask me anything or say "open positions".`
      : `Welcome to SlimeWire. I can navigate anywhere, check any CA, set your quick buy, and run trades from chat.${memoryLine} Try "whats cooking" or paste a token address.`,
    actions: [
      { label: "Live Terminal", type: "open_tab", tab: "terminal" },
      { label: "Positions", type: "open_tab", tab: "positions" }
    ]
  });
}

function ogreBriefHtml() {
  const items = [...ogreBriefItems(), `🧾 Proof wall is public - slimewire.org/proof`];
  return `
    <section class="trade-card ogre-brief-card">
      <div class="trade-head">
        <div>
          <h3>Ogre Brief</h3>
          <p>Right now, at a glance.</p>
        </div>
      </div>
      <ul class="ogre-brief-list">
        ${items.map((item) => `<li>${escapeHtml(item)}</li>`).join("")}
      </ul>
    </section>
  `;
}

// --- SlimeShield receipts panel: public proof the shield works -----------------
function shieldReceiptsPanelHtml() {
  ensureShieldReceiptsData();
  const data = state.shieldReceipts;
  if (!data) {
    return `
      <section class="trade-card shield-receipts-card">
        <div class="trade-head"><div><h3>SlimeShield Receipts</h3><p>Loading flagged-token outcomes...</p></div></div>
      </section>
    `;
  }
  const rugged = (data.receipts || []).filter((item) => item.outcome === "rugged").slice(0, 8);
  const stats = data.stats || {};
  return `
    <section class="trade-card shield-receipts-card">
      <div class="trade-head">
        <div>
          <h3>SlimeShield Receipts</h3>
          <p>Every AVOID/RISK flag is recorded, then we check what happened. ${Number.isFinite(stats.hitRatePct) && stats.hitRatePct !== null ? `<strong>${stats.hitRatePct}%</strong> of resolved flags went on to rug or die.` : "Outcomes resolve after the market moves."}</p>
        </div>
        <span>${stats.flagged || 0} flagged | ${stats.rugged || 0} rugged | ${stats.watching || 0} watching</span>
      </div>
      ${rugged.length ? `
        <div class="table-list compact-table">
          ${rugged.map((item) => `
            <article class="row-card">
              <div class="row-main">
                <strong>$${escapeHtml(item.symbol || shortAddress(item.mint))} <span class="negative">rugged</span></strong>
                <span>Flagged ${escapeHtml(item.verdict)} (score ${escapeHtml(String(item.score))}) ${item.confirmedAfterMinutes ? `- confirmed dead within ${escapeHtml(formatReceiptDuration(item.confirmedAfterMinutes))}` : ""}</span>
                ${item.summary ? `<small>${escapeHtml(item.summary)}</small>` : ""}
              </div>
              <div class="card-actions compact">
                <button data-copy="${escapeHtml(item.mint)}">Copy CA</button>
              </div>
            </article>
          `).join("")}
        </div>` : `<p class="trade-status">No confirmed rugs in the log yet - receipts build up as the shield flags live tokens.</p>`}
    </section>
  `;
}

function formatReceiptDuration(minutes) {
  const value = Number(minutes) || 0;
  if (value < 90) return `${value} min`;
  if (value < 48 * 60) return `${Math.round(value / 60)}h`;
  return `${Math.round(value / 1440)}d`;
}

let shieldReceiptsFetchedAt = 0;
function ensureShieldReceiptsData() {
  if (Date.now() - shieldReceiptsFetchedAt < 5 * 60 * 1000) return;
  shieldReceiptsFetchedAt = Date.now();
  void api("/api/web/shield/receipts").then((data) => {
    state.shieldReceipts = data;
    if (state.activeTab === "tek") render();
  }).catch(() => {
    // Receipts are informational; never block the hub.
  });
  void api("/api/web/proof").then((data) => {
    state.proofStats = data?.alpha || null;
  }).catch(() => {
    // Brief line is optional.
  });
}

