// Map the simple configurator controls (investment / duration / mode /
// aggressiveness) onto the tested SlimeBot backend params. Conservative:
// total spend stays bounded near the chosen investment, caps preserved.
function readVolumeBotForm() {
  const mode = state.slimeBotMode === "spam" ? "spam" : "smart";
  const aggr = ["low", "med", "high"].includes(state.slimeBotAggr) ? state.slimeBotAggr : "med";
  const tokenMint = $("[data-vbot-token]")?.value?.trim() || "";
  const robinhood = /^0x[0-9a-fA-F]{40}$/.test(tokenMint);
  const investment = Math.max(0.05, Math.min(robinhood ? 5 : 50, Number($("[data-vbot-invest-num]")?.value || $("[data-vbot-invest]")?.value || "1")));
  const durationMin = Math.max(20, Math.min(360, Number($("[data-vbot-duration]")?.value || "60")));

  const aggrMap = {
    low: { delaySecs: 30, buyBias: 55, walletCount: 4 },
    med: { delaySecs: 12, buyBias: 60, walletCount: 6 },
    high: { delaySecs: 5, buyBias: 70, walletCount: 10 }
  };
  const a = aggrMap[aggr];
  const rolling = mode === "smart"; // Smart = fresh wallet each round (organic)
  const stepSec = a.delaySecs * (rolling ? 4 : 1);
  let rounds = Math.round((durationMin * 60) / stepSec);
  // Bound rounds so total spend never blows past the chosen investment.
  rounds = Math.max(1, Math.min(250, rounds, Math.floor(investment / 0.01)));
  const buyAmountSol = Math.max(0.005, Math.min(0.5, investment / rounds));

  return {
    tokenMint,
    chain: robinhood ? "robinhood" : "solana",
    sourceWalletIndex: $("[data-vbot-source]")?.value || "1",
    rollingWallets: rolling,
    autoCreateWallets: !rolling,
    walletCount: String(a.walletCount),
    fundPerWalletSol: rolling ? "" : (buyAmountSol + 0.02).toFixed(4),
    buyAmountSol: buyAmountSol.toFixed(4),
    sellPercent: "100",
    buyBias: String(a.buyBias),
    cycles: String(rounds),
    maxRounds: String(rounds),
    delaySecs: String(a.delaySecs),
    slippageBps: "400",
    sweepBack: true,
    walletIndexes: [],
    walletGroup: "",
    keepDust: true,
    offsetSell: Boolean($("[data-vbot-offset]")?.checked),
    staggerPattern: ["steady", "waves", "organic", "ladder"].includes(state.slimeBotStagger) ? state.slimeBotStagger : "steady",
    investment,
    durationMin,
    mode,
    aggr
  };
}

function setVolumeBotStatus(message) {
  state.volumeBotStatus = String(message || "");
  const node = $("[data-vbot-status]");
  if (node) node.textContent = state.volumeBotStatus;
}

async function loadVolumeBots({ silent = true } = {}) {
  try {
    const [solResult, rhResult] = await Promise.allSettled([
      api("/api/web/volume-bot"),
      api("/api/web/rh/volume/status")
    ]);
    const solBots = solResult.status === "fulfilled" && Array.isArray(solResult.value?.bots) ? solResult.value.bots : [];
    const rhBot = rhResult.status === "fulfilled" ? rhVolumeBotFromStatus(rhResult.value) : null;
    state.volumeBots = rhBot ? [rhBot, ...solBots] : solBots;
    if (state.activeTab === "volume") render();
  } catch (error) {
    if (!silent) setError(error.message);
  }
}

async function startVolumeBot() {
  if (state.volumeBotBusy) return;
  const form = readVolumeBotForm();
  if (!form.tokenMint) {
    setVolumeBotStatus("Paste a token CA first.");
    return;
  }
  const durLabel = form.durationMin >= 60 ? `${(form.durationMin / 60).toFixed(form.durationMin % 60 ? 1 : 0)}h` : `${form.durationMin}m`;
  const rh = form.chain === "robinhood";
  const rhRounds = Math.max(1, Math.min(10, Math.round(form.durationMin / 20)));
  const confirmed = await slimeConfirm({
    title: "Start SlimeBot",
    lines: rh ? [
      "This spends REAL SOL.",
      `Robinhood token: ${form.tokenMint}`,
      `${form.investment} SOL is converted once for Wallet ${form.sourceWalletIndex}.`,
      `${rhRounds} randomized Robinhood buy + sell round(s); trade sizing is automatic.`,
      "Stop waits for the current on-chain action to finish."
    ] : [
      "This spends REAL SOL.",
      `Token: ${form.tokenMint}`,
      `${form.mode === "smart" ? "Smart" : "Spam"} mode, ${form.aggr.toUpperCase()} aggressiveness.`,
      `Deploys up to ~${form.investment} SOL over ${durLabel} from your source wallet,`,
      `as ${form.cycles} round(s) of randomized ~${form.buyAmountSol} SOL buys / sells.`,
      "Sweeps funds back to the source wallet when done."
    ],
    confirmLabel: "Start SlimeBot"
  });
  if (!confirmed) return;
  state.volumeBotBusy = true;
  setVolumeBotStatus("Funding wallets and starting bot...");
  render();
  try {
    const data = await api(rh ? "/api/web/rh/volume/start" : "/api/web/volume-bot/start", {
      method: "POST",
      body: JSON.stringify(rh ? {
        tokenAddress: form.tokenMint,
        walletIndexes: [form.sourceWalletIndex],
        rounds: String(rhRounds),
        payCurrency: "SOL",
        fundSolPerWallet: String(form.investment)
      } : form),
      dedupe: false,
      timeoutMs: API_LONG_ACTION_TIMEOUT_MS
    });
    state.volumeBotBusy = false;
    if (data.bot) {
      state.volumeBots = [data.bot, ...state.volumeBots.filter((bot) => bot.id !== data.bot.id)];
    }
    setVolumeBotStatus(data.bot?.message || (rh ? "SOL conversion started. Robinhood volume will begin automatically." : "SlimeBot started."));
    render();
    void loadVolumeBots();
  } catch (error) {
    state.volumeBotBusy = false;
    await loadVolumeBots({ silent: true }).catch(() => {});
    setVolumeBotStatus(error.message);
    render();
  }
}

async function stopVolumeBot(planId) {
  if (!planId) return;
  try {
    setVolumeBotStatus("Stopping bot...");
    const robinhood = planId === "rh-volume-current";
    const data = await api(robinhood ? "/api/web/rh/volume/stop" : "/api/web/volume-bot/stop", {
      method: "POST",
      body: JSON.stringify(robinhood ? {} : { planId }),
      dedupe: false,
      timeoutMs: API_LONG_ACTION_TIMEOUT_MS
    });
    if (data.bot) {
      state.volumeBots = state.volumeBots.map((bot) => (bot.id === data.bot.id ? data.bot : bot));
    }
    setVolumeBotStatus(data.bot?.message || (robinhood ? "Stopping after the current Robinhood action." : "Stop requested."));
    render();
    void loadVolumeBots();
  } catch (error) {
    setVolumeBotStatus(error.message);
  }
}

async function releaseVolumeBot(planId) {
  if (!planId) return;
  const confirmed = await slimeConfirm({
    title: "Halt & Release Run",
    lines: [
      "Stops this run permanently and releases its source wallet now.",
      "No new buys or sells will be sent. A transaction already submitted before the settlement check may still finish.",
      "Any unresolved ghost wallet stays encrypted and can be recovered later with Sweep background wallets."
    ],
    confirmLabel: "Halt & Release"
  });
  if (!confirmed) return;
  try {
    setVolumeBotStatus("Halting run and releasing source wallet...");
    const data = await api("/api/web/volume-bot/release", {
      method: "POST",
      body: JSON.stringify({ planId, confirmRelease: true }),
      dedupe: false,
      timeoutMs: API_LONG_ACTION_TIMEOUT_MS
    });
    if (data.bot) {
      state.volumeBots = state.volumeBots.map((bot) => (bot.id === data.bot.id ? data.bot : bot));
    }
    setVolumeBotStatus(data.bot?.message || "Run halted. You can start a new SlimeBot now.");
    render();
    void loadVolumeBots();
  } catch (error) {
    setVolumeBotStatus(error.message);
  }
}

