function livePairAvatarHtml(row, options = {}) {
  const label = String(row.symbol || row.name || row.shortMint || "?").trim().slice(0, 2).toUpperCase() || "?";
  const imageUrl = livePairImageUrl(row);
  const mint = String(row.tokenMint || row.mint || row.tokenAddress || row.address || "").trim();
  const avatarKey = `token:${String(mint || row.symbol || label).trim().toLowerCase()}`;
  const tokenAvatarFixOn = featureEnabled("tokenAvatarFixEnabled", true);
  const explicitAvatarState = String(row.avatarState || "").trim().toLowerCase();
  const avatarBlocked = explicitAvatarState === "missing" || explicitAvatarState === "failed";
  const cachedAvatarReady = Boolean(row.avatarUrl) && (!explicitAvatarState || explicitAvatarState === "ready");
  // Use the backend token-image proxy whenever we have a mint and the avatar
  // isn't known-missing. The proxy resolves the real image + redirects to it
  // server-side, so even fresh "pending" coins get a picture without waiting
  // for the row to carry a fully resolved avatarUrl.
  const proxyUrl = mint && !avatarBlocked ? normalizeImageUrl(tokenImageProxyUrl(row)) : "";
  const src = tokenAvatarFixOn
    ? stableAvatarSrc(avatarKey, cachedAvatarReady ? row.avatarUrl : "", proxyUrl, avatarBlocked ? "" : imageUrl)
    : stableAvatarSrc(avatarKey, proxyUrl, imageUrl);
  const backupSrc = tokenAvatarFixOn && !avatarBlocked
    ? (proxyUrl && src !== proxyUrl ? proxyUrl : (imageUrl && imageUrl !== src ? imageUrl : ""))
    : "";
  const priority = Boolean(options.priority);
  const loading = priority ? "eager" : "lazy";
  const fetchPriority = priority ? "high" : "low";
  const avatarState = explicitAvatarState || (src ? "ready" : "missing");
  if (src) {
    const backupAttr = backupSrc ? ` data-backup-src="${escapeHtml(backupSrc)}"` : "";
    const proxyAttr = proxyUrl ? ` data-proxy-src="${escapeHtml(proxyUrl)}"` : "";
    return `<div class="live-pair-avatar" data-avatar-state="${escapeHtml(avatarState)}"><img src="${escapeHtml(src)}"${backupAttr}${proxyAttr} data-avatar-src="${escapeHtml(src)}" data-avatar-key="${escapeHtml(avatarKey)}" alt="${escapeHtml(row.symbol || row.name || "Token")}" loading="${loading}" decoding="sync" fetchpriority="${fetchPriority}" width="42" height="42" referrerpolicy="no-referrer" onload="window.__slimeRememberAvatar&&window.__slimeRememberAvatar(this.dataset.avatarKey,this.currentSrc||this.src);" onerror="window.__slimeAvatarLoadFailed&&window.__slimeAvatarLoadFailed(this);"><span>${escapeHtml(label)}</span></div>`;
  }
  return `<div class="live-pair-avatar fallback" data-avatar-state="${escapeHtml(avatarState)}"><span>${escapeHtml(label)}</span></div>`;
}

function tokenMascotIndex(value = "") {
  const text = String(value || "");
  let total = 0;
  for (let index = 0; index < text.length; index += 1) total += text.charCodeAt(index);
  return (total % 5) + 1;
}

function tokenMascotSrc(value = "") {
  return `./assets/slimewire/png/token-mascots/token-mascot-${tokenMascotIndex(value)}.png`;
}

function livePairShareText(row) {
  return `Live pair ${row.symbol || shortAddress(row.tokenMint)} spotted on SlimeWire: MC ${row.marketCapLabel || "n/a"}, liq ${row.liquidityLabel || "n/a"}, age ${row.pairAgeLabel || formatAgeFromRow(row) || "age unknown"}.`;
}

function sniperHtml() {
  const modes = [
    ["safe", "Safe Picks"],
    ["smart", "Smart Accumulation"],
    ["fast", "Fast Movers"],
    ["pumpsnipe", "PumpSnipe"],
    ["moonshot", "Low MC"],
    ["meme", "Narratives"],
    ["long", "Long Term"]
  ];
  const activeLabel = modes.find(([mode]) => mode === state.scanMode)?.[1] || "Picks";
  return `
    <section class="terminal-layout sniper-terminal">
      <main class="terminal-main">
        <div class="terminal-title-row">
          <div>
            <h3>OgreSniper</h3>
            <p>${escapeHtml(sniperModeDescription(state.scanMode))}</p>
          </div>
          <span>${escapeHtml(activeLabel)}</span>
        </div>
        <div class="mode-row terminal-modes">
          ${modes.map(([mode, label]) => `<button data-scan-mode="${mode}" data-active="${state.scanMode === mode}">${label}</button>`).join("")}
        </div>
        <div class="section-actions terminal-actions">
          <button class="primary" data-refresh-scan>Refresh ${escapeHtml(activeLabel)}</button>
          <button data-tab="trade">Trade Desk</button>
          <button data-tab="bundle">Bundle</button>
          <button data-tab="live">Cooks</button>
        </div>
        ${state.scan ? sniperRowsHtml() : emptyState("No scan loaded", "Pick a mode or tap Refresh Picks.")}
      </main>
      <aside class="trade-side order-ticket-stack">
        ${sniperSetupHtml()}
      </aside>
    </section>
  `;
}

function sniperModeDescription(mode) {
  const descriptions = {
    safe: "Safer-looking picks with stronger liquidity, cleaner trend, lower risk flags, and no obvious dump/sell-pressure pattern.",
    smart: "Accumulation-style picks: buyer pressure, steady volume, and cleaner momentum without obvious sell pressure.",
    fast: "Fast movers with volume picking up and a cleaner short-term trend for quicker in-and-out trades.",
    pumpsnipe: "Very early pump-style launches, usually lower market cap, with enough volume/liquidity to attempt a quick trade.",
    moonshot: "Low market-cap picks targeting the 4k-40k range, with fallback up to 60k only when the cleaner low-cap pool is thin.",
    meme: "Narrative picks based on token metadata/keywords plus volume and trend checks. Add a social feed later for true social velocity.",
    long: "Longer-hold candidates with steadier accumulation signals and less short-term dump pressure."
  };
  return descriptions[mode] || descriptions.safe;
}

