  walletLaunch: '<rect x="3" y="7" width="18" height="12" rx="2.5"/><path d="M3 11h18"/><circle cx="16.5" cy="14" r="1.2"/><path d="M12 3l2.1 4.2 4.6.7-3.3 3.2.8 4.6L12 13.5l-4.2 2.2.8-4.6-3.3-3.2 4.6-.7z"/>',
